import { test, expect } from '@playwright/test';

test('Amazon SG backpack image loads', async ({ page }) => {
  // 1. Launch browser → Amazon SG
  await page.goto('https://www.amazon.sg/', { waitUntil: 'domcontentloaded' });

  // 2. Search for "backpack"
  const searchBox = page.locator('input[name="field-keywords"]');
  await expect(searchBox).toBeVisible();
  await searchBox.fill('backpack');
  await page.getByRole('button', { name: 'Go' }).click();

  // Wait for search results to load
  const firstProduct = page.locator('div.s-main-slot div[data-component-type="s-search-result"]').first();
  await expect(firstProduct).toBeVisible();

  // 3. Open first product
  const productLink = firstProduct.locator('a[href*="/dp/"]');
  await expect(productLink).toBeVisible();
  await productLink.click();

  // Wait for product page to load
  await page.waitForLoadState('domcontentloaded');

  // 4. Validate product image is loaded (img not broken)
  // Amazon product image: id="landingImage"
  const productImg = page.locator('img#landingImage');
  await expect(productImg).toBeVisible();

  // Check image is loaded and not broken
  const imgLoaded = await productImg.evaluate((img: HTMLImageElement) => {
    return img && img.complete && img.naturalWidth > 0;
  });
  expect(imgLoaded).toBe(true);

  // 5. Close browser (handled automatically by Playwright)
});
